/*! marked.js minimal - sufficient for docs rendering */
(function(root){
"use strict";
function marked(src){
  return new Parser().parse(new Lexer().lex(src));
}
marked.parse = marked;

// Lexer
function Lexer(){this.tokens=[];}
Lexer.prototype.lex=function(src){
  src=src.replace(/\r\n|\r/g,"\n").replace(/\t/g,"    ");
  return this.blockTokens(src,this.tokens),this.tokens;
};
Lexer.prototype.blockTokens=function(src,tokens){
  while(src){
    var cap;
    // Fenced code block
    if(cap=/^(`{3,}|~{3,})([^\n]*)\n([\s\S]*?)\1\s*(?:\n|$)/.exec(src)){
      src=src.slice(cap[0].length);
      tokens.push({type:"code",lang:cap[2].trim(),text:cap[3]});continue;
    }
    // Heading
    if(cap=/^(#{1,6}) +([^\n]+?)(?:\n|$)/.exec(src)){
      src=src.slice(cap[0].length);
      tokens.push({type:"heading",depth:cap[1].length,text:cap[2]});continue;
    }
    // Horizontal rule
    if(cap=/^(?:(?:- *){3,}|(?:\* *){3,}|(?:_ *){3,})(?:\n|$)/.exec(src)){
      src=src.slice(cap[0].length);
      tokens.push({type:"hr"});continue;
    }
    // Blockquote
    if(cap=/^( {0,3}> ?(paragraph|[^\n]*)(?:\n|$))+/.exec(src)){
      src=src.slice(cap[0].length);
      var bqText=cap[0].replace(/^ {0,3}> ?/gm,"");
      tokens.push({type:"blockquote",tokens:new Lexer().blockTokens(bqText,[])});continue;
    }
    // Table
    if(cap=/^([^\n]+)\n {0,3}(\|? *(?::?-+:? *\|?)+)(?:\n((?:(?:[^\n]*)\n?)*))?\n*/.exec(src)){
      var header=cap[1].trim(),align=cap[2],rows=cap[3]?cap[3].split("\n").filter(Boolean):[];
      if(/^ *[-:| ]+$/.test(align)){
        src=src.slice(cap[0].length);
        tokens.push({type:"table",header:header.split("|").map(function(h){return h.trim();}).filter(Boolean),
          rows:rows.map(function(r){return r.split("|").map(function(c){return c.trim();}).filter(Boolean);})});continue;
      }
    }
    // Unordered list
    if(cap=/^( {0,3})((?:- |\* |\+ )[^\n]+(?:\n(?! {0,3}(?:- |\* |\+ ))[^\n]+)*(?:\n|$))+/.exec(src)){
      src=src.slice(cap[0].length);
      var items=cap[0].match(/^ {0,3}(?:- |\* |\+ )([^\n]+(?:\n(?! {0,3}(?:- |\* |\+ ))[^\n]+)*)/gm)||[];
      tokens.push({type:"list",ordered:false,items:items.map(function(i){return i.replace(/^ {0,3}(?:- |\* |\+ )/,"").trim();})});continue;
    }
    // Ordered list
    if(cap=/^( {0,3})((?:\d+\. )[^\n]+(?:\n(?! {0,3}\d+\. )[^\n]+)*(?:\n|$))+/.exec(src)){
      src=src.slice(cap[0].length);
      var oitems=cap[0].match(/^ {0,3}\d+\. ([^\n]+(?:\n(?! {0,3}\d+\. )[^\n]+)*)/gm)||[];
      tokens.push({type:"list",ordered:true,items:oitems.map(function(i){return i.replace(/^ {0,3}\d+\. /,"").trim();})});continue;
    }
    // Blank line
    if(cap=/^\n+/.exec(src)){src=src.slice(cap[0].length);continue;}
    // Paragraph
    if(cap=/^([^\n]+(?:\n(?!#{1,6} |`{3}|~{3}|> | {0,3}(?:-|\*|\+|\d+\.) )[^\n]+)*)/.exec(src)){
      src=src.slice(cap[0].length);
      tokens.push({type:"paragraph",text:cap[0].trim()});continue;
    }
    // Skip unknown
    src=src.slice(1);
  }
  return tokens;
};

// Parser
function Parser(){}
Parser.prototype.parse=function(tokens){
  var out="";
  for(var i=0;i<tokens.length;i++) out+=this.tok(tokens[i]);
  return out;
};
Parser.prototype.tok=function(token){
  switch(token.type){
    case"heading":return"<h"+token.depth+" id=\""+slug(token.text)+"\">"+inline(token.text)+"</h"+token.depth+">\n";
    case"hr":return"<hr>\n";
    case"blockquote":return"<blockquote>"+this.parse(token.tokens)+"</blockquote>\n";
    case"code":return"<pre><code"+(token.lang?' class="language-'+esc(token.lang)+'"':"")+">"+esc(token.text)+"</code></pre>\n";
    case"table":
      var th=token.header.map(function(h){return"<th>"+inline(h)+"</th>";}).join("");
      var tb=token.rows.map(function(r){return"<tr>"+r.map(function(c){return"<td>"+inline(c)+"</td>";}).join("")+"</tr>";}).join("\n");
      return"<table><thead><tr>"+th+"</tr></thead><tbody>"+tb+"</tbody></table>\n";
    case"list":
      var tag=token.ordered?"ol":"ul";
      var items=token.items.map(function(i){return"<li>"+inline(i)+"</li>";}).join("\n");
      return"<"+tag+">\n"+items+"\n</"+tag+">\n";
    case"paragraph":return"<p>"+inline(token.text)+"</p>\n";
    default:return"";
  }
};

function inline(src){
  return src
    .replace(/`([^`]+)`/g,function(_,c){return"<code>"+esc(c)+"</code>";})
    .replace(/\*\*([^*]+)\*\*/g,"<strong>$1</strong>")
    .replace(/\*([^*]+)\*/g,"<em>$1</em>")
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g,function(_,t,h){
      var ext=/^https?:\/\//.test(h);
      return'<a href="'+esc(h)+'"'+(ext?' target="_blank" rel="noopener"':"")+">"+t+"</a>";
    })
    .replace(/&(?!amp;|lt;|gt;|quot;)/g,"&amp;")
    ;
}
function esc(s){return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");}
function slug(s){return s.toLowerCase().replace(/[^\w\s-]/g,"").replace(/\s+/g,"-");}

if(typeof module!=="undefined")module.exports=marked;
else root.marked=marked;
}(typeof globalThis!=="undefined"?globalThis:typeof window!=="undefined"?window:this));
